  1→/**
  2→ * 飞书 Webhook 服务器
  3→ *
  4→ * 提供 HTTP 接口接收飞书消息，处理后返回响应
  5→ */
  6→
  7→const http = require('http');
  8→const fs = require('fs');
  9→const path = require('path');
 10→const { exec } = require('child_process');
 11→const crypto = require('crypto');
 12→
 13→// 配置
 14→const CONFIG = {
 15→  port: 3000,
 16→  commandPrefix: '!cmd ',
 17→  timeout: 30000,
 18→  workingDir: __dirname
 19→};
 20→
 21→// 飞书配置（从 clawdbot 读取）
 22→let FEISHU_CONFIG;
 23→try {
 24→  FEISHU_CONFIG = JSON.parse(
 25→    fs.readFileSync('C:\\Users\\Administrator\\.moltbot\\credentials\\feishu.json', 'utf8')
 26→  );
 27→} catch (error) {
 28→  console.warn('⚠️ 无法读取飞书配置');
 29→  FEISHU_CONFIG = {};
 30→}
 31→
 32→// 日志文件
 33→const LOG_FILE = path.join(__dirname, 'webhook-server.log');
 34→
 35→/**
 36→ * 记录日志
 37→ */
 38→function log(message, level = 'INFO') {
 39→  const timestamp = new Date().toISOString();
 40→  const logMessage = `[${timestamp}] [${level}] ${message}\n`;
 41→
 42→  console.log(logMessage.trim());
 43→  fs.appendFileSync(LOG_FILE, logMessage);
 44→}
 45→
 46→/**
 47→ * 执行命令
 48→ */
 49→function executeCommand(command) {
 50→  return new Promise((resolve, reject) => {
 51→    log(`执行命令: ${command}`, 'INFO');
 52→
 53→    exec(command, {
 54→      cwd: CONFIG.workingDir,
 55→      timeout: CONFIG.timeout,
 56→      maxBuffer: 1024 * 1024 * 10 // 10MB
 57→    }, (error, stdout, stderr) => {
 58→      if (error) {
 59→        log(`命令执行失败: ${error.message}`, 'ERROR');
 60→        resolve({
 61→          success: false,
 62→          exitCode: error.code || -1,
 63→          output: stderr || stdout || error.message
 64→        });
 65→      } else {
 66→        log(`命令执行成功，退出码: 0`, 'INFO');
 67→        resolve({
 68→          success: true,
 69→          exitCode: 0,
 70→          output: stdout || stderr || '(无输出)'
 71→        });
 72→      }
 73→    });
 74→  });
 75→}
 76→
 77→/**
 78→ * 获取系统状态
 79→ */
 80→function getStatus() {
 81→  return {
 82→    success: true,
 83→    status: {
 84→      time: new Date().toLocaleString('zh-CN'),
 85→      workingDir: CONFIG.workingDir,
 86→      platform: process.platform,
 87→      nodeVersion: process.version,
 88→      uptime: process.uptime().toFixed(0) + 's',
 89→      memory: (process.memoryUsage().heapUsed / 1024 / 1024).toFixed(2) + ' MB'
 90→    }
 91→  };
 92→}
 93→
 94→/**
 95→ * 处理飞书消息
 96→ */
 97→async function handleFeishuMessage(text, sender = 'unknown') {
 98→  log(`收到消息 (${sender}): ${text}`, 'INFO');
 99→
100→  const trimmedText = text.trim();
101→
102→  // 处理不同类型的消息
103→  if (trimmedText.startsWith(CONFIG.commandPrefix)) {
104→    const command = trimmedText.slice(CONFIG.commandPrefix.length).trim();
105→    const result = await executeCommand(command);
106→
107→    let responseText;
108→    if (result.success) {
109→      responseText = `✅ 命令执行成功\n\n命令: ${command}\n\n输出:\n${truncateText(result.output, 2000)}`;
110→    } else {
111→      responseText = `❌ 命令执行失败 (退出码: ${result.exitCode})\n\n命令: ${command}\n\n错误:\n${truncateText(result.output, 2000)}`;
112→    }
113→
114→    return {
115→      success: true,
116→      response: responseText
117→    };
118→
119→  } else if (trimmedText === '!status' || trimmedText === '状态') {
120→    const status = getStatus();
121→    const statusText = `📊 系统状态\n\n` +
122→      `⏰ 时间: ${status.status.time}\n` +
123→      `📂 工作目录: ${status.status.workingDir}\n` +
124→      `💻 平台: ${status.status.platform}\n` +
125→      `🔧 Node版本: ${status.status.nodeVersion}\n` +
126→      `⏳ 运行时间: ${status.status.uptime}\n` +
127→      `💾 内存使用: ${status.status.memory}`;
128→
129→    return {
130→      success: true,
131→      response: statusText
132→    };
133→
134→  } else if (trimmedText === '!help' || trimmedText === '帮助') {
135→    const helpText = `📖 远程终端助手使用帮助\n\n` +
136→      `🔧 执行命令:\n` +
137→      `  ${CONFIG.commandPrefix}<命令>\n` +
138→      `  示例: ${CONFIG.commandPrefix}dir\n\n` +
139→      `📊 查询状态:\n` +
140→      `  !status 或 状态\n\n` +
141→      `❓ 帮助:\n` +
142→      `  !help 或 帮助`;
143→
144→    return {
145→      success: true,
146→      response: helpText
147→    };
148→
149→  } else {
150→    return {
151→      success: true,
152→      response: `❓ 未知命令: ${trimmedText}\n\n发送 "!help" 查看帮助`
153→    };
154→  }
155→}
