 1→import * as Lark from "@larksuiteoapi/node-sdk";
 2→import type { FeishuConfig, FeishuDomain } from "./types.js";
 3→import { resolveFeishuCredentials } from "./accounts.js";
 4→
 5→let cachedClient: Lark.Client | null = null;
 6→let cachedConfig: { appId: string; appSecret: string; domain: FeishuDomain } | null = null;
 7→
 8→function resolveDomain(domain: FeishuDomain) {
 9→  return domain === "lark" ? Lark.Domain.Lark : Lark.Domain.Feishu;
10→}
11→
12→export function createFeishuClient(cfg: FeishuConfig): Lark.Client {
13→  const creds = resolveFeishuCredentials(cfg);
14→  if (!creds) {
15→    throw new Error("Feishu credentials not configured (appId, appSecret required)");
16→  }
17→
18→  if (
19→    cachedClient &&
20→    cachedConfig &&
21→    cachedConfig.appId === creds.appId &&
22→    cachedConfig.appSecret === creds.appSecret &&
23→    cachedConfig.domain === creds.domain
24→  ) {
25→    return cachedClient;
26→  }
27→
28→  const client = new Lark.Client({
29→    appId: creds.appId,
30→    appSecret: creds.appSecret,
31→    appType: Lark.AppType.SelfBuild,
32→    domain: resolveDomain(creds.domain),
33→  });
34→
35→  cachedClient = client;
36→  cachedConfig = { appId: creds.appId, appSecret: creds.appSecret, domain: creds.domain };
37→
38→  return client;
39→}
40→
41→export function createFeishuWSClient(cfg: FeishuConfig): Lark.WSClient {
42→  const creds = resolveFeishuCredentials(cfg);
43→  if (!creds) {
44→    throw new Error("Feishu credentials not configured (appId, appSecret required)");
45→  }
46→
47→  return new Lark.WSClient({
48→    appId: creds.appId,
49→    appSecret: creds.appSecret,
50→    domain: resolveDomain(creds.domain),
51→    loggerLevel: Lark.LoggerLevel.info,
52→  });
53→}
54→
55→export function createEventDispatcher(cfg: FeishuConfig): Lark.EventDispatcher {
56→  const creds = resolveFeishuCredentials(cfg);
57→  return new Lark.EventDispatcher({
58→    encryptKey: creds?.encryptKey,
59→    verificationToken: creds?.verificationToken,
60→  });
61→}
62→
63→export function clearClientCache() {
64→  cachedClient = null;
65→  cachedConfig = null;
66→}
