394→export function parseFeishuMessageEvent(
395→  event: FeishuMessageEvent,
396→  botOpenId?: string,
397→): FeishuMessageContext {
398→  const rawContent = parseMessageContent(event.message.content, event.message.message_type);
399→  const mentionedBot = checkBotMentioned(event, botOpenId);
400→  const content = stripBotMention(rawContent, event.message.mentions);
401→
402→  return {
403→    chatId: event.message.chat_id,
404→    messageId: event.message.message_id,
405→    senderId: event.sender.sender_id.user_id || event.sender.sender_id.open_id || "",
406→    senderOpenId: event.sender.sender_id.open_id || "",
407→    chatType: event.message.chat_type,
408→    mentionedBot,
409→    rootId: event.message.root_id || undefined,
410→    parentId: event.message.parent_id || undefined,
411→    content,
412→    contentType: event.message.message_type,
413→  };
414→}
