416→export async function handleFeishuMessage(params: {
417→  cfg: ClawdbotConfig;
418→  event: FeishuMessageEvent;
419→  botOpenId?: string;
420→  runtime?: RuntimeEnv;
421→  chatHistories?: Map<string, HistoryEntry[]>;
422→}): Promise<void> {
423→  const { cfg, event, botOpenId, runtime, chatHistories } = params;
424→  const feishuCfg = cfg.channels?.feishu as FeishuConfig | undefined;
425→  const log = runtime?.log ?? console.log;
426→  const error = runtime?.error ?? console.error;
427→
428→  let ctx = parseFeishuMessageEvent(event, botOpenId);
429→  const rawContent = ctx.content.trim();
430→
431→  // ========== 远程终端命令处理 ==========
432→  // 检查是否是远程终端命令（以 ! 开头）
433→  if (rawContent.startsWith('!')) {
434→    log(`feishu: 检测到远程终端命令: ${rawContent}`);
435→
436→    try {
437→      // 调用本地 webhook 服务器
438→      const webhookResponse = await fetch('http://localhost:3000/api/command', {
439→        method: 'POST',
440→        headers: { 'Content-Type': 'application/json' },
441→        body: JSON.stringify({
442→          command: rawContent,
443→          sender: ctx.senderOpenId
444→        })
445→      });
446→
447→      if (webhookResponse.ok) {
448→        const result = await webhookResponse.json();
449→
450→        // 发送结果回飞书
451→        const { sendMessageFeishu } = await import("./send.js");
452→        await sendMessageFeishu({
453→          cfg,
454→          to: ctx.chatId,
455→          text: result.response || result.error || '命令执行完成',
456→        });
457→
458→        log(`feishu: 远程命令执行成功，结果已发送回飞书`);
459→        return; // 不继续处理，直接返回
460→      } else {
461→        throw new Error(`Webhook 服务器返回错误: ${webhookResponse.status}`);
462→      }
463→    } catch (err) {
464→      log(`feishu: 调用 webhook 服务器失败: ${String(err)}`);
465→
466→      // 提示用户启动服务器
467→      const { sendMessageFeishu } = await import("./send.js");
468→      await sendMessageFeishu({
469→        cfg,
470→        to: ctx.chatId,
471→        text: `❌ 无法连接到远程终端服务器\n\n请确保运行了: node feishu-webhook-server.js\n\n错误: ${String(err)}`,
472→      });
473→      return;
474→    }
475→  }
476→  // ========== 远程终端命令处理结束 ==========
477→  const isGroup = ctx.chatType === "group";
478→
479→  // Resolve sender display name (best-effort) so the agent can attribute messages correctly.
480→  const senderName = await resolveFeishuSenderName({
481→    feishuCfg,
482→    senderOpenId: ctx.senderOpenId,
483→    log,
484→  });
485→  if (senderName) ctx = { ...ctx, senderName };
486→
487→  log(`feishu: received message from ${ctx.senderOpenId} in ${ctx.chatId} (${ctx.chatType})`);
488→
489→  const historyLimit = Math.max(
490→    0,
491→    feishuCfg?.historyLimit ?? cfg.messages?.groupChat?.historyLimit ?? DEFAULT_GROUP_HISTORY_LIMIT,
492→  );
493→
494→  if (isGroup) {
495→    const groupPolicy = feishuCfg?.groupPolicy ?? "open";
496→    const groupAllowFrom = feishuCfg?.groupAllowFrom ?? [];
497→    const groupConfig = resolveFeishuGroupConfig({ cfg: feishuCfg, groupId: ctx.chatId });
498→
499→    const senderAllowFrom = groupConfig?.allowFrom ?? groupAllowFrom;
500→    const allowed = isFeishuGroupAllowed({
501→      groupPolicy,
502→      allowFrom: senderAllowFrom,
503→      senderId: ctx.senderOpenId,
504→      senderName: ctx.senderName,
505→    });
506→
507→    if (!allowed) {
508→      log(`feishu: sender ${ctx.senderOpenId} not in group allowlist`);
509→      return;
510→    }
511→
512→    const { requireMention } = resolveFeishuReplyPolicy({
513→      isDirectMessage: false,
514→      globalConfig: feishuCfg,
515→      groupConfig,
516→    });
517→
518→    if (requireMention && !ctx.mentionedBot) {
519→      log(`feishu: message in group ${ctx.chatId} did not mention bot, recording to history`);
520→      if (chatHistories) {
521→        recordPendingHistoryEntryIfEnabled({
522→          historyMap: chatHistories,
523→          historyKey: ctx.chatId,
524→          limit: historyLimit,
525→          entry: {
526→            sender: ctx.senderOpenId,
527→            body: `${ctx.senderName ?? ctx.senderOpenId}: ${ctx.content}`,
528→            timestamp: Date.now(),
529→            messageId: ctx.messageId,
530→          },
531→        });
532→      }
533→      return;
534→    }
535→  } else {
536→    const dmPolicy = feishuCfg?.dmPolicy ?? "pairing";
537→    const allowFrom = feishuCfg?.allowFrom ?? [];
538→
539→    if (dmPolicy === "allowlist") {
540→      const match = resolveFeishuAllowlistMatch({
541→        allowFrom,
542→        senderId: ctx.senderOpenId,
543→      });
544→      if (!match.allowed) {
545→        log(`feishu: sender ${ctx.senderOpenId} not in DM allowlist`);
546→        return;
547→      }
548→    }
549→  }
550→
551→  try {
552→    const core = getFeishuRuntime();
553→
554→    // In group chats, the session is scoped to the group, but the *speaker* is the sender.
555→    // Using a group-scoped From causes the agent to treat different users as the same person.
556→    const feishuFrom = `feishu:${ctx.senderOpenId}`;
557→    const feishuTo = isGroup ? `chat:${ctx.chatId}` : `user:${ctx.senderOpenId}`;
558→
559→    const route = core.channel.routing.resolveAgentRoute({
560→      cfg,
561→      channel: "feishu",
562→      peer: {
563→        kind: isGroup ? "group" : "dm",
564→        id: isGroup ? ctx.chatId : ctx.senderOpenId,
565→      },
566→    });
567→
568→    const preview = ctx.content.replace(/\s+/g, " ").slice(0, 160);
569→    const inboundLabel = isGroup
570→      ? `Feishu message in group ${ctx.chatId}`
571→      : `Feishu DM from ${ctx.senderOpenId}`;
572→
573→    core.system.enqueueSystemEvent(`${inboundLabel}: ${preview}`, {
574→      sessionKey: route.sessionKey,
575→      contextKey: `feishu:message:${ctx.chatId}:${ctx.messageId}`,
576→    });
577→
578→    // Resolve media from message
579→    const mediaMaxBytes = (feishuCfg?.mediaMaxMb ?? 30) * 1024 * 1024; // 30MB default
580→    const mediaList = await resolveFeishuMediaList({
581→      cfg,
582→      messageId: ctx.messageId,
583→      messageType: event.message.message_type,
584→      content: event.message.content,
585→      maxBytes: mediaMaxBytes,
586→      log,
587→    });
588→    const mediaPayload = buildFeishuMediaPayload(mediaList);
589→
590→    // Fetch quoted/replied message content if parentId exists
591→    let quotedContent: string | undefined;
592→    if (ctx.parentId) {
593→      try {
594→        const quotedMsg = await getMessageFeishu({ cfg, messageId: ctx.parentId });
595→        if (quotedMsg) {
596→          quotedContent = quotedMsg.content;
597→          log(`feishu: fetched quoted message: ${quotedContent?.slice(0, 100)}`);
598→        }
599→      } catch (err) {
600→        log(`feishu: failed to fetch quoted message: ${String(err)}`);
601→      }
602→    }
603→
604→    const envelopeOptions = core.channel.reply.resolveEnvelopeFormatOptions(cfg);
605→
606→    // Build message body with quoted content if available
607→    let messageBody = ctx.content;
608→    if (quotedContent) {
609→      messageBody = `[Replying to: "${quotedContent}"]\n\n${ctx.content}`;
610→    }
611→
612→    // Include a readable speaker label so the model can attribute instructions.
613→    // (DMs already have per-sender sessions, but the prefix is still useful for clarity.)
614→    const speaker = ctx.senderName ?? ctx.senderOpenId;
615→    messageBody = `${speaker}: ${messageBody}`;
616→
617→    const envelopeFrom = isGroup ? `${ctx.chatId}:${ctx.senderOpenId}` : ctx.senderOpenId;
618→
619→    const body = core.channel.reply.formatAgentEnvelope({
620→      channel: "Feishu",
621→      from: envelopeFrom,
622→      timestamp: new Date(),
623→      envelope: envelopeOptions,
624→      body: messageBody,
625→    });
626→
627→    let combinedBody = body;
628→    const historyKey = isGroup ? ctx.chatId : undefined;
629→
630→    if (isGroup && historyKey && chatHistories) {
631→      combinedBody = buildPendingHistoryContextFromMap({
632→        historyMap: chatHistories,
633→        historyKey,
634→        limit: historyLimit,
635→        currentMessage: combinedBody,
636→        formatEntry: (entry) =>
637→          core.channel.reply.formatAgentEnvelope({
638→            channel: "Feishu",
639→            // Preserve speaker identity in group history as well.
640→            from: `${ctx.chatId}:${entry.sender}`,
641→            timestamp: entry.timestamp,
642→            body: entry.body,
643→            envelope: envelopeOptions,
644→          }),
645→      });
646→    }
647→
648→    const ctxPayload = core.channel.reply.finalizeInboundContext({
649→      Body: combinedBody,
650→      RawBody: ctx.content,
651→      CommandBody: ctx.content,
652→      From: feishuFrom,
653→      To: feishuTo,
654→      SessionKey: route.sessionKey,
655→      AccountId: route.accountId,
656→      ChatType: isGroup ? "group" : "direct",
657→      GroupSubject: isGroup ? ctx.chatId : undefined,
658→      SenderName: ctx.senderName ?? ctx.senderOpenId,
659→      SenderId: ctx.senderOpenId,
660→      Provider: "feishu" as const,
661→      Surface: "feishu" as const,
662→      MessageSid: ctx.messageId,
663→      Timestamp: Date.now(),
664→      WasMentioned: ctx.mentionedBot,
665→      CommandAuthorized: true,
666→      OriginatingChannel: "feishu" as const,
667→      OriginatingTo: feishuTo,
668→      ...mediaPayload,
669→    });
670→
671→    const { dispatcher, replyOptions, markDispatchIdle } = createFeishuReplyDispatcher({
672→      cfg,
673→      agentId: route.agentId,
674→      runtime: runtime as RuntimeEnv,
675→      chatId: ctx.chatId,
676→      replyToMessageId: ctx.messageId,
677→    });
678→
679→    log(`feishu: dispatching to agent (session=${route.sessionKey})`);
680→
681→    const { queuedFinal, counts } = await core.channel.reply.dispatchReplyFromConfig({
682→      ctx: ctxPayload,
683→      cfg,
684→      dispatcher,
685→      replyOptions,
686→    });
687→
688→    markDispatchIdle();
689→
690→    if (isGroup && historyKey && chatHistories) {
691→      clearHistoryEntriesIfEnabled({
692→        historyMap: chatHistories,
693→        historyKey,
694→        limit: historyLimit,
695→      });
696→    }
697→
698→    log(`feishu: dispatch complete (queuedFinal=${queuedFinal}, replies=${counts.final})`);
699→  } catch (err) {
700→    error(`feishu: failed to dispatch message: ${String(err)}`);
701→  }
702→}
