  9→export type MonitorFeishuOpts = {
 10→  config?: ClawdbotConfig;
 11→  runtime?: RuntimeEnv;
 12→  abortSignal?: AbortSignal;
 13→  accountId?: string;
 14→};
 15→
 16→let currentWsClient: Lark.WSClient | null = null;
 17→let botOpenId: string | undefined;
 18→
 19→async function fetchBotOpenId(cfg: FeishuConfig): Promise<string | undefined> {
 20→  try {
 21→    const result = await probeFeishu(cfg);
 22→    return result.ok ? result.botOpenId : undefined;
 23→  } catch {
 24→    return undefined;
 25→  }
 26→}
