 57→async function monitorWebSocket(params: {
 58→  cfg: ClawdbotConfig;
 59→  feishuCfg: FeishuConfig;
 60→  runtime?: RuntimeEnv;
 61→  abortSignal?: AbortSignal;
 62→}): Promise<void> {
 63→  const { cfg, feishuCfg, runtime, abortSignal } = params;
 64→  const log = runtime?.log ?? console.log;
 65→  const error = runtime?.error ?? console.error;
 66→
 67→  log("feishu: starting WebSocket connection...");
 68→
 69→  const wsClient = createFeishuWSClient(feishuCfg);
 70→  currentWsClient = wsClient;
 71→
 72→  const chatHistories = new Map<string, HistoryEntry[]>();
 73→
 74→  const eventDispatcher = createEventDispatcher(feishuCfg);
 75→
 76→  eventDispatcher.register({
 77→    "im.message.receive_v1": async (data) => {
 78→      try {
 79→        const event = data as unknown as FeishuMessageEvent;
 80→        await handleFeishuMessage({
 81→          cfg,
 82→          event,
 83→          botOpenId,
 84→          runtime,
 85→          chatHistories,
 86→        });
 87→      } catch (err) {
 88→        error(`feishu: error handling message event: ${String(err)}`);
 89→      }
 90→    },
 91→    "im.message.message_read_v1": async () => {
 92→      // Ignore read receipts
 93→    },
 94→    "im.chat.member.bot.added_v1": async (data) => {
 95→      try {
 96→        const event = data as unknown as FeishuBotAddedEvent;
 97→        log(`feishu: bot added to chat ${event.chat_id}`);
 98→      } catch (err) {
 99→        error(`feishu: error handling bot added event: ${String(err)}`);
100→      }
101→    },
102→    "im.chat.member.bot.deleted_v1": async (data) => {
103→      try {
104→        const event = data as unknown as { chat_id: string };
105→        log(`feishu: bot removed from chat ${event.chat_id}`);
106→      } catch (err) {
107→        error(`feishu: error handling bot removed event: ${String(err)}`);
108→      }
109→    },
110→  });
111→
112→  return new Promise((resolve, reject) => {
113→    const cleanup = () => {
114→      if (currentWsClient === wsClient) {
115→        currentWsClient = null;
116→      }
117→    };
118→
119→    const handleAbort = () => {
120→      log("feishu: abort signal received, stopping WebSocket client");
121→      cleanup();
122→      resolve();
123→    };
124→
125→    if (abortSignal?.aborted) {
126→      cleanup();
127→      resolve();
128→      return;
129→    }
130→
131→    abortSignal?.addEventListener("abort", handleAbort, { once: true });
132→
133→    try {
134→      wsClient.start({
135→        eventDispatcher,
136→      });
137→
138→      log("feishu: WebSocket client started");
139→    } catch (err) {
140→      cleanup();
141→      abortSignal?.removeEventListener("abort", handleAbort);
142→      reject(err);
143→    }
144→  });
145→}
146→
147→export function stopFeishuMonitor(): void {
148→  if (currentWsClient) {
149→    currentWsClient = null;
150→  }
151→}
