 89→export type SendFeishuMessageParams = {
 90→  cfg: ClawdbotConfig;
 91→  to: string;
 92→  text: string;
 93→  replyToMessageId?: string;
 94→};
 95→
 96→export async function sendMessageFeishu(params: SendFeishuMessageParams): Promise<FeishuSendResult> {
 97→  const { cfg, to, text, replyToMessageId } = params;
 98→  const feishuCfg = cfg.channels?.feishu as FeishuConfig | undefined;
 99→  if (!feishuCfg) {
100→    throw new Error("Feishu channel not configured");
101→  }
102→
103→  const client = createFeishuClient(feishuCfg);
104→  const receiveId = normalizeFeishuTarget(to);
105→  if (!receiveId) {
106→    throw new Error(`Invalid Feishu target: ${to}`);
107→  }
108→
109→  const receiveIdType = resolveReceiveIdType(receiveId);
110→  const tableMode = getFeishuRuntime().channel.text.resolveMarkdownTableMode({
111→    cfg,
112→    channel: "feishu",
113→  });
114→  const messageText = getFeishuRuntime().channel.text.convertMarkdownTables(text ?? "", tableMode);
115→
116→  const content = JSON.stringify({ text: messageText });
117→
118→  if (replyToMessageId) {
119→    const response = await client.im.message.reply({
120→      path: { message_id: replyToMessageId },
121→      data: {
122→        content,
123→        msg_type: "text",
124→      },
125→    });
126→
127→    if (response.code !== 0) {
128→      throw new Error(`Feishu reply failed: ${response.msg || `code ${response.code}`}`);
129→    }
130→
131→    return {
132→      messageId: response.data?.message_id ?? "unknown",
133→      chatId: receiveId,
134→    };
135→  }
136→
137→  const response = await client.im.message.create({
138→    params: { receive_id_type: receiveIdType },
139→    data: {
140→      receive_id: receiveId,
141→      content,
142→      msg_type: "text",
143→    },
144→  });
145→
146→  if (response.code !== 0) {
147→    throw new Error(`Feishu send failed: ${response.msg || `code ${response.code}`}`);
148→  }
149→
150→  return {
151→    messageId: response.data?.message_id ?? "unknown",
152→    chatId: receiveId,
153→  };
154→}
