 30→export type CreateFeishuReplyDispatcherParams = {
 31→  cfg: ClawdbotConfig;
 32→  agentId: string;
 33→  runtime: RuntimeEnv;
 34→  chatId: string;
 35→  replyToMessageId?: string;
 36→};
 37→
 38→export function createFeishuReplyDispatcher(params: CreateFeishuReplyDispatcherParams) {
 39→  const core = getFeishuRuntime();
 40→  const { cfg, agentId, chatId, replyToMessageId } = params;
 41→
 42→  const prefixContext = createReplyPrefixContext({
 43→    cfg,
 44→    agentId,
 45→  });
 46→
 47→  // Feishu doesn't have a native typing indicator API.
 48→  // We use message reactions as a typing indicator substitute.
 49→  let typingState: TypingIndicatorState | null = null;
 50→
 51→  const typingCallbacks = createTypingCallbacks({
 52→    start: async () => {
 53→      if (!replyToMessageId) return;
 54→      typingState = await addTypingIndicator({ cfg, messageId: replyToMessageId });
 55→      params.runtime.log?.(`feishu: added typing indicator reaction`);
 56→    },
 57→    stop: async () => {
 58→      if (!typingState) return;
 59→      await removeTypingIndicator({ cfg, state: typingState });
 60→      typingState = null;
 61→      params.runtime.log?.(`feishu: removed typing indicator reaction`);
 62→    },
 63→    onStartError: (err) => {
 64→      logTypingFailure({
 65→        log: (message) => params.runtime.log?.(message),
 66→        channel: "feishu",
 67→        action: "start",
 68→        error: err,
 69→      });
 70→    },
 71→    onStopError: (err) => {
 72→      logTypingFailure({
 73→        log: (message) => params.runtime.log?.(message),
 74→        channel: "feishu",
 75→        action: "stop",
 76→        error: err,
 77→      });
 78→    },
 79→  });
 80→
 81→  const textChunkLimit = core.channel.text.resolveTextChunkLimit({
 82→    cfg,
 83→    channel: "feishu",
 84→    defaultLimit: 4000,
 85→  });
 86→  const chunkMode = core.channel.text.resolveChunkMode(cfg, "feishu");
 87→  const tableMode = core.channel.text.resolveMarkdownTableMode({
 88→    cfg,
 89→    channel: "feishu",
 90→  });
 91→
 92→  const { dispatcher, replyOptions, markDispatchIdle } =
 93→    core.channel.reply.createReplyDispatcherWithTyping({
 94→      responsePrefix: prefixContext.responsePrefix,
 95→      responsePrefixContextProvider: prefixContext.responsePrefixContextProvider,
 96→      humanDelay: core.channel.reply.resolveHumanDelayConfig(cfg, agentId),
 97→      onReplyStart: typingCallbacks.onReplyStart,
 98→      deliver: async (payload: ReplyPayload) => {
 99→        params.runtime.log?.(`feishu deliver called: text=${payload.text?.slice(0, 100)}`);
100→        const text = payload.text ?? "";
101→        if (!text.trim()) {
102→          params.runtime.log?.(`feishu deliver: empty text, skipping`);
103→          return;
104→        }
105→
106→        // Check render mode: auto (default), raw, or card
107→        const feishuCfg = cfg.channels?.feishu as FeishuConfig | undefined;
108→        const renderMode = feishuCfg?.renderMode ?? "auto";
109→
110→        // Determine if we should use card for this message
111→        const useCard =
112→          renderMode === "card" || (renderMode === "auto" && shouldUseCard(text));
113→
114→        if (useCard) {
115→          // Card mode: send as interactive card with markdown rendering
116→          const chunks = core.channel.text.chunkTextWithMode(text, textChunkLimit, chunkMode);
117→          params.runtime.log?.(`feishu deliver: sending ${chunks.length} card chunks to ${chatId}`);
118→          for (const chunk of chunks) {
119→            await sendMarkdownCardFeishu({
120→              cfg,
121→              to: chatId,
122→              text: chunk,
123→              replyToMessageId,
124→            });
125→          }
126→        } else {
127→          // Raw mode: send as plain text with table conversion
128→          const converted = core.channel.text.convertMarkdownTables(text, tableMode);
129→          const chunks = core.channel.text.chunkTextWithMode(converted, textChunkLimit, chunkMode);
130→          params.runtime.log?.(`feishu deliver: sending ${chunks.length} text chunks to ${chatId}`);
131→          for (const chunk of chunks) {
132→            await sendMessageFeishu({
133→              cfg,
134→              to: chatId,
135→              text: chunk,
136→              replyToMessageId,
137→            });
138→          }
139→        }
140→      },
141→      onError: (err, info) => {
142→        params.runtime.error?.(`feishu ${info.kind} reply failed: ${String(err)}`);
143→        typingCallbacks.onIdle?.();
144→      },
145→      onIdle: typingCallbacks.onIdle,
146→    });
147→
148→  return {
149→    dispatcher,
150→    replyOptions: {
151→      ...replyOptions,
152→      onModelSelected: prefixContext.onModelSelected,
153→    },
154→    markDispatchIdle,
155→  };
156→}
