30→  const creds = resolveFeishuCredentials(feishuCfg);
31→
32→  return {
33→    accountId: params.accountId?.trim() || DEFAULT_ACCOUNT_ID,
34→    enabled,
35→    configured: Boolean(creds),
36→    appId: creds?.appId,
37→    domain: creds?.domain ?? "feishu",
