 68→export type FeishuMessageEvent = {
 69→  sender: {
 70→    sender_id: {
 71→      open_id?: string;
 72→      user_id?: string;
 73→      union_id?: string;
 74→    };
 75→    sender_type?: string;
 76→    tenant_key?: string;
 77→  };
 78→  message: {
 79→    message_id: string;
 80→    root_id?: string;
 81→    parent_id?: string;
 82→    chat_id: string;
 83→    chat_type: "p2p" | "group";
 84→    message_type: string;
 85→    content: string;
 86→    mentions?: Array<{
 87→      key: string;
 88→      id: {
 89→        open_id?: string;
 90→        user_id?: string;
 91→        union_id?: string;
 92→      };
 93→      name: string;
 94→      tenant_key?: string;
 95→    }>;
 96→  };
