 99→export type FeishuBotAddedEvent = {
100→  chat_id: string;
101→  operator_id: {
102→    open_id?: string;
103→    user_id?: string;
104→    union_id?: string;
105→  };
106→  external: boolean;
107→  operator_tenant_key?: string;
